+func TestResolveAgentName_GeminiFallback(t *testing.T) {
+	t.Parallel()
+	p := tmux.Pane{Title: "", Type: tmux.AgentGemini, Index: 0}
+	got := resolveAgentName(p)
+	if got != "GeminiAgent0" {
+		t.Errorf("resolveAgentName gemini = %q, want 'GeminiAgent0'", got)
+	}
+}
