+func TestResolveAgentName_UnknownType(t *testing.T) {
+	t.Parallel()
+	p := tmux.Pane{Title: "", Type: "unknown", Index: 1}
+	got := resolveAgentName(p)
+	if got != "" {
+		t.Errorf("resolveAgentName unknown = %q, want empty", got)
+	}
+}
